module accu(
    input clk,
    input rst_n,
    input [7:0] data_in,
    input valid_in,
    output reg valid_out,
    output reg [9:0] data_out
);

reg [9:0] accu_reg;
reg [2:0] count;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        accu_reg <= 10'b0;
        count <= 3'b0;
        valid_out <= 1'b0;
        data_out <= 10'b0;
    end
    else begin
        if (valid_in) begin
            if (count < 3'd4) begin
                accu_reg <= accu_reg + data_in;
                count <= count + 1'b1;
                valid_out <= 1'b0;
            end
            else begin
                data_out <= accu_reg;
                valid_out <= 1'b1;
                count <= 3'b0;
                accu_reg <= 10'b0;
            end
        end
        else begin
            valid_out <= 1'b0;
        end
    end
end

endmodule
